## 9. src/lib/api.ts — Edge Function Helpers

```typescript
import { supabase } from './supabase';

const SUPABASE_URL = process.env.EXPO_PUBLIC_SUPABASE_URL || '';

async function getAuthHeaders() {
  const { data: { session } } = await supabase.auth.getSession();
  return {
    'Authorization': `Bearer ${session?.access_token || ''}`,
    'Content-Type': 'application/json',
  };
}

export async function callEdgeFunction(name: string, body: any) {
  const headers = await getAuthHeaders();
  const response = await fetch(`${SUPABASE_URL}/functions/v1/${name}`, {
    method: 'POST',
    headers,
    body: JSON.stringify(body),
  });
  if (!response.ok) throw new Error(`Edge function ${name} failed: ${response.status}`);
  return response.json();
}

export async function streamEdgeFunction(name: string, body: any, onChunk: (text: string) => void): Promise<string> {
  const headers = await getAuthHeaders();
  const response = await fetch(`${SUPABASE_URL}/functions/v1/${name}`, {
    method: 'POST',
    headers,
    body: JSON.stringify(body),
  });

  if (!response.ok) throw new Error(`Edge function ${name} failed: ${response.status}`);
  if (!response.body) throw new Error('No response body for streaming');

  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  let fullText = '';

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    const chunk = decoder.decode(value, { stream: true });

    // Parse SSE data
    const lines = chunk.split('\n');
    for (const line of lines) {
      if (line.startsWith('data: ')) {
        const data = line.slice(6);
        if (data === '[DONE]') continue;
        try {
          const parsed = JSON.parse(data);
          const content = parsed.choices?.[0]?.delta?.content || '';
          if (content) {
            fullText += content;
            onChunk(content);
          }
        } catch { /* skip non-JSON lines */ }
      }
    }
  }
  return fullText;
}
```

## 10. src/lib/spaced-repetition.ts — SM-2 Algorithm

```typescript
export interface SM2Card {
  ease_factor: number;
  interval: number;
  repetitions: number;
  next_review: string;
}

export type Quality = 0 | 1 | 2 | 3 | 4 | 5;

// Quality mapping for UI: Again=1, Hard=2, Good=4, Easy=5
export const QualityLabels = [
  { label: 'Again', quality: 1 as Quality, color: '#EF4444' },
  { label: 'Hard', quality: 2 as Quality, color: '#FF9800' },
  { label: 'Good', quality: 4 as Quality, color: '#4CAF50' },
  { label: 'Easy', quality: 5 as Quality, color: '#D4AF37' },
];

export function sm2(card: SM2Card, quality: Quality): SM2Card {
  let { ease_factor, interval, repetitions } = card;

  if (quality < 3) {
    // Failed — reset
    repetitions = 0;
    interval = 1;
  } else {
    // Passed
    if (repetitions === 0) interval = 1;
    else if (repetitions === 1) interval = 3;
    else interval = Math.round(interval * ease_factor);
    repetitions += 1;
  }

  // Update ease factor
  ease_factor = Math.max(1.3, ease_factor + 0.1 - (5 - quality) * (0.08 + (5 - quality) * 0.02));

  const next = new Date();
  next.setDate(next.getDate() + interval);

  return {
    ease_factor,
    interval,
    repetitions,
    next_review: next.toISOString(),
  };
}
```

## 11. src/hooks/useStreamingChat.ts

```typescript
import { useState, useCallback } from 'react';
import { useChatStore } from '@/stores/chatStore';
import { streamEdgeFunction } from '@/lib/api';

export function useStreamingChat() {
  const { setIsStreaming, setStreamingText, appendStreamingText, addMessage, setSuggestions } = useChatStore();

  const sendMessage = useCallback(async (
    conversationId: string,
    messages: Array<{ role: string; content: string }>,
  ) => {
    setIsStreaming(true);
    setStreamingText('');
    setSuggestions([]);

    try {
      const fullText = await streamEdgeFunction('chat', {
        conversation_id: conversationId,
        messages,
      }, (chunk) => {
        appendStreamingText(chunk);
      });

      // Parse suggestions from response
      const suggestionsMatch = fullText.match(/\[SUGGESTIONS\]:\s*([\s\S]*?)$/);
      if (suggestionsMatch) {
        const suggestions = suggestionsMatch[1]
          .split(/\d+\.\s+/)
          .filter(s => s.trim())
          .map(s => s.trim());
        setSuggestions(suggestions);
      }

      // Add the complete message
      const cleanContent = fullText.replace(/\[SUGGESTIONS\]:[\s\S]*$/, '').trim();
      addMessage({
        id: Date.now().toString(),
        conversation_id: conversationId,
        role: 'assistant',
        content: cleanContent,
        is_starred: false,
        is_hots: false,
        blooms_level: null,
        created_at: new Date().toISOString(),
      });

      return cleanContent;
    } catch (error) {
      console.error('Chat error:', error);
      throw error;
    } finally {
      setIsStreaming(false);
      setStreamingText('');
    }
  }, []);

  return { sendMessage };
}
```

